import './App.css';
import './index.css';

function App() {
  return (
    <div className="App">
       <div>
             <h2 className="title">Счётчик:</h2>
             <h1 className="output">0</h1>
             <button type='button' className="Minus">- Minus</button>
             <button type='button' className="Plus">Plus +</button>
       </div>
    </div>
  );
}

export default App;
